assert.match(linkCards, /const hasCustomMakeHref = typeof makeHref === 'function';[\s\S]*baseHref = hasCustomMakeHref \? makeHref\(loc, parsed\) : defaultMakeHref\(loc\);[\s\S]*if \(!baseHref \|\| baseHref === '#'\) return '';[\s\S]*const href = buildCardHref\(loc, parsed\);\n\s*if \(!href\) return;/, 'internal link cards should skip cards when injected route helpers return no href');
assert.doesNotMatch(linkCards, /searchParams\.set\('id'/, 'internal link cards should not manually reconstruct post routes when route helpers return null');
assert.doesNotMatch(linkCards, /^const\s+mdCache\s*=\s*new Map\(\)/m, 'internal link-card markdown cache should not be module-level mutable state');
assert.match(linkCards, /function createLinkCardState\(\) \{[\s\S]*mdCache: new Map\(\)[\s\S]*export function createLinkCardHydrator\(options = \{\}\) \{[\s\S]*const runtime = createLinkCardRuntime\(options\)[\s\S]*hydrate\(container, hydrateOptions = \{\}\)/, 'internal link-card cache should be scoped to explicit hydrator runtimes');

assert.match(nativeCss, /press-search\.box,[\s\S]*press-theme-controls\.box,[\s\S]*press-toc\.box\s*\{\s*display: block;/, 'native component hosts should preserve block layout');
assert.match(nativeCss, /\.protected-post-excerpt[\s\S]*color: var\(--text\);/, 'native locked article panel should style the public excerpt separately from the generic unlock copy');

assert.match(editorBlocksBlockCoreModel, /const BLOCK_TYPES = new Set\(\[[\s\S]*'table'[\s\S]*\]\);/, 'block core model should register a visual table block type');
assert.match(editorBlocksTableModel, /export function parseTableBlock\(raw\)[\s\S]*parsePipeTableSeparatorCells[\s\S]*headers[\s\S]*alignments[\s\S]*rows/, 'table model should parse supported pipe tables into structured table data');
assert.match(editorBlocksModel, /export \{[\s\S]*parseTableBlock[\s\S]*serializeTable[\s\S]*\} from '\.\/editor-blocks-table-model\.js';/, 'block model should delegate visual table parsing and serialization through the table model boundary');
assert.match(editorBlocksTableSession, /const renderBlock = \(body, block, index\) => \{[\s\S]*blocks-table-cell-input[\s\S]*blocks-table-align-\$\{align \|\| 'default'\}/, 'table session should render editable table cell inputs with alignment hooks');
assert.match(editorBlocksBlockTypeSessions, /table: \(body, block, index\) => tableSession\?\.renderBlock\?\.\(body, block, index\)/, 'block type session assembly should pass table rendering through the body-session renderer map');
assert.match(editorBlocksBodySession, /type === 'table'[\s\S]*callRenderer\(renderers, 'table', body, block, index\)/, 'block body session should delegate visual table bodies through the table session boundary');
assert.match(editorBlocksTableSession, /const createControls = \(block, index\) => \{[\s\S]*blocks-table-align-select[\s\S]*blocks-table-add-row[\s\S]*blocks-table-add-column[\s\S]*blocks-table-delete-row[\s\S]*blocks-table-delete-column/, 'table session should expose table row, column, and alignment controls');
assert.match(editorBlocksHeadSession, /if \(block\.type === 'table'\) appendIf\(head, tableSession\?\.createControls\?\.\(block, index\)\);/, 'block head session should delegate table toolbar controls through the table session boundary');
assert.match(editorBlocksActiveSession, /syncActiveTableAlignmentFromEditable\(\s*activeBlock,\s*editable \|\| \(hasBlocksState\('getActiveEditable'\) \? blocksState\.getActiveEditable\(\) : null\) \|\| activeElementFrom\(runtime\)\s*\);/, 'active block selection should sync table alignment from the focused table cell');
assert.match(editorBlocksTableSession, /const setAlignmentSelectValue = \(alignment, value\) => \{[\s\S]*alignment\.value = normalized;[\s\S]*option\.selected = option\.value === normalized;[\s\S]*const syncActiveAlignmentFromEditable = \(activeBlock, editable, stateBlocks = \[\]\) => \{[\s\S]*positionFromCellInput\(cell\)[\s\S]*setActivePosition\(block, normalizePosition\(block, position\)\);/, 'table alignment control should force the select value and selected option from active table cell DOM state');
assert.match(editorBlocksTableSession, /const isActivePosition = \(block, position\) => \{[\s\S]*blocksState\.activeTableCellMatches\(block && block\.id, position\)[\s\S]*const applyIfCurrent = \(\) => \{[\s\S]*isActivePosition\(block, normalized\)[\s\S]*requestFrame\(applyIfCurrent\)[\s\S]*setTimer\(applyIfCurrent\);/, 'deferred table alignment sync should not overwrite newer active table cells');
assert.doesNotMatch(`${editorBlocks}\n${editorBlocksTableSession}`, /elements\.blocksList/, 'table alignment sync should use the editor list element available in this closure');
assert.doesNotMatch(`${editorBlocks}\n${editorBlocksTableSession}`, /cssEscape/, 'table alignment sync should not depend on unavailable global CSS escape helpers');
assert.match(indexEditorHtml, /\.blocks-table-wrap[\s\S]*\.blocks-table-cell-input[\s\S]*\.blocks-table-align-left[\s\S]*\.blocks-table-align-center[\s\S]*\.blocks-table-align-right/, 'editor shell should style visual table blocks and alignment classes');
assert.match(i18nEn, /table: 'This table-like Markdown is kept as source because it is not a supported standard pipe table\.'/, 'sourceReason.table should describe unsupported table fallback');
